#!/usr/bin/env node
// Healzy V2 — Self-Extracting Installer
// Generated: 2026-03-13T16:51:56.844Z
// Files: 74

'use strict';
const fs = require('fs');
const path = require('path');

const DEST = process.argv[2] || path.join(process.cwd(), 'healzy-v2');
const B64 = '';

console.log('\n╔══════════════════════════════════════╗');
console.log('║   Healzy V2 — Extracting Project    ║');
console.log('╚══════════════════════════════════════╝\n');
console.log('Destination:', DEST);

const files = JSON.parse(Buffer.from(B64, 'base64').toString('utf8'));
const keys = Object.keys(files);
let written = 0;

for (const rel of keys) {
  const full = path.join(DEST, rel);
  fs.mkdirSync(path.dirname(full), { recursive: true });
  fs.writeFileSync(full, files[rel], 'utf8');
  written++;
  if (written % 10 === 0) process.stdout.write(`\r  [${written}/${keys.length}] files...`);
}

console.log(`\n\n✓ Extracted ${written} files to ${DEST}\n`);
console.log('Next steps:');
console.log('  cd', path.basename(DEST));
console.log('  cp .env.example backend/.env   # add your API keys!');
console.log('  npm run install:all');
console.log('  npm run db:migrate');
console.log('  npm run dev');
console.log('\n  Frontend → http://localhost:3000');
console.log('  Backend  → http://localhost:3001');
console.log('  Swagger  → http://localhost:3001/docs\n');
